func TestParseCurrency(t *testing.T) {
	tests := []struct {
		input   string
		want    float64
		wantErr bool
	}{
		{"2399", 2399.0, false},
		{"2399.00", 2399.0, false},
		{"R$2399", 2399.0, false},
		{"r$1500", 1500.0, false},
		{"1.500,00", 0, true}, // comma-thousands not supported
		{"", 0, true},
		{"abc", 0, true},
	}
	for _, tc := range tests {
		got, err := parseCurrency(tc.input)
		if tc.wantErr {
			if err == nil {
				t.Errorf("parseCurrency(%q) expected error, got %v", tc.input, got)
			}
			continue
		}
		if err != nil {
			t.Errorf("parseCurrency(%q) unexpected error: %v", tc.input, err)
			continue
		}
		if got != tc.want {
			t.Errorf("parseCurrency(%q) = %v, want %v", tc.input, got, tc.want)
		}
	}
}

func TestExtractCartTotal(t *testing.T) {
	tests := []struct {
		name string
		data string
		want float64
	}{
		{
			name: "total field",
			data: `{"total":1850.50,"items":[]}`,
			want: 1850.50,
		},
		{
			name: "totalValue field",
			data: `{"totalValue":2100.00}`,
			want: 2100.00,
		},
		{
			name: "nested summary",
			data: `{"summary":{"total":950.75}}`,
			want: 950.75,
		},
		{
			name: "no total",
			data: `{"items":[]}`,
			want: 0,
		},
		{
			name: "invalid json",
			data: `not json`,
			want: 0,
		},
	}
	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			got := extractCartTotal(json.RawMessage(tc.data))
			if got != tc.want {
				t.Errorf("extractCartTotal(%q) = %v, want %v", tc.data, got, tc.want)
			}
		})
	}
}

func TestExtractCatalogItemsForCashback(t *testing.T) {
	data := `{"items":[
		{"id":"1","name":"Arroz","price":9.99},
		{"id":"2","name":"Feijao","price":5.99},
		{"id":"3","name":"NoPrice"}
	]}`
	items := extractCatalogItemsForCashback(json.RawMessage(data), nil)
	// Item without price should be excluded
	if len(items) != 2 {
		t.Errorf("expected 2 items (one without price excluded), got %d", len(items))
	}
}
